    def _encode_disk_value(self, value: Any) -> bytes:
        """Pickle and optionally compress a value, prefixing it with a magic header."""
        payload = cloudpickle.dumps(value)
        codec_byte = _COMPRESSION_CODECS.get(self.compress, 0x00)
